import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.HttpEntity;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpMethod;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.client.RestTemplate;

import java.net.InetAddress;
import java.net.UnknownHostException;
import java.util.Arrays;
import java.util.List;

@RestController
@RequestMapping("/webhook")
public class WebhookHandler {

    @Autowired
    private RestTemplate restTemplate;

    private static final List<String> ALLOWLISTED_DESTINATIONS = Arrays.asList(
        "https://example.com",
        "https://another-example.com"
    );

    @PostMapping("/process")
    public ResponseEntity<String> processWebhook(@RequestBody String url) {
        if (!isAllowed(url)) {
            return ResponseEntity.status(403).body("Access denied");
        }

        try {
            ResponseEntity<String> response = restTemplate.exchange(
                url,
                HttpMethod.GET,
                new HttpEntity<>(new HttpHeaders()),
                String.class
            );
            return ResponseEntity.ok(response.getBody());
        } catch (Exception e) {
            return ResponseEntity.status(500).body("Failed to fetch content");
        }
    }

    private boolean isAllowed(String url) {
        try {
            InetAddress address = InetAddress.getByName(url);
            if (isInternalOrPrivateIP(address)) {
                return false;
            }
            return ALLOWLISTED_DESTINATIONS.stream().anyMatch(allowedUrl -> allowedUrl.equals(url));
        } catch (UnknownHostException e) {
            return false;
        }
    }

    private boolean isInternalOrPrivateIP(InetAddress address) {
        byte[] ip = address.getAddress();
        if (ip.length == 4) { // IPv4
            int firstOctet = ip[0] & 0xFF;
            return (firstOctet >= 10 && firstOctet <= 255) ||
                   (firstOctet == 172 && (ip[1] & 0xFF) >= 16 && (ip[1] & 0xFF) <= 31) ||
                   (firstOctet == 192 && (ip[1] & 0xFF) == 168);
        } else if (ip.length == 16) { // IPv6
            return false; // Add checks for IPv6 private ranges if needed
        }
        return true;
    }
}